/**
 * POST /api/query/:collection
 *
 * Body JSON:
 * {
 *   "filter":     { "age": { "$gt": 18 }, "name": { "$regex": "^J" } },
 *   "projection": { "password": 0 },
 *   "sort":       { "createdAt": -1 },
 *   "limit":      50,
 *   "skip":       0
 * }
 */
app.post('/api/query/:collection', async (req, res) => {
  try {
    const { collection } = req.params;
    const { filter, projection, sort, limit, skip } = req.body;

    const results = await queryBuilder(collection, filter, projection, sort, limit, skip);

    return res.json({
      success: true,
      count: results.length,
      data: results,
    });
  } catch (err) {
    console.error('[API ERROR]', err.message);
    return res.status(400).json({
      success: false,
      error: err.message,
    });
  }
});

/**
 * GET /api/query/:collection
 * Accepts filter, projection, sort as JSON-encoded query parameters.
 * Useful for simple GET-based queries.
 *
 * Example: /api/query/users?filter={"age":{"$gt":18}}&sort={"createdAt":-1}&limit=10
 */
app.get('/api/query/:collection', async (req, res) => {
  try {
    const { collection } = req.params;

    let filter = {};
    let projection = null;
    let sort = null;

    if (req.query.filter) {
      filter = JSON.parse(req.query.filter);
    }
    if (req.query.projection) {
      projection = JSON.parse(req.query.projection);
    }
    if (req.query.sort) {
      sort = JSON.parse(req.query.sort);
    }

    const limit = req.query.limit ? parseInt(req.query.limit, 10) : 100;
    const skip = req.query.skip ? parseInt(req.query.skip, 10) : 0;

    const results = await queryBuilder(collection, filter, projection, sort, limit, skip);

    return res.json({
      success: true,
      count: results.length,
      data: results,
    });
  } catch (err) {
    console.error('[API ERROR]', err.message);
    return res.status(400).json({
      success: false,
      error: err.message,
    });
  }
});

/**
 * POST /api/count/:collection
 * Returns the count of documents matching the filter.
 */
app.post('/api/count/:collection', async (req, res) => {
  try {
    const { collection } = req.params;
    const { filter } = req.body;

    if (!/^[a-zA-Z_][a-zA-Z0-9_]*$/.test(collection)) {
      throw new Error('Invalid collection name');
    }

    const safeFilter = sanitiseFilter(filter || {});
    const count = await db.collection(collection).countDocuments(safeFilter);

    return res.json({ success: true, count });
  } catch (err) {
    console.error('[API ERROR]', err.message);
    return res.status(400).json({ success: false, error: err.message });
  }
});

/**
 * POST /api/distinct/:collection/:field
 * Returns distinct values for a field, optionally filtered.
 */
app.post('/api/distinct/:collection/:field', async (req, res) => {
  try {
    const { collection, field } = req.params;
    const { filter } = req.body;

    if (!/^[a-zA-Z_][a-zA-Z0-9_]*$/.test(collection)) {
      throw new Error('Invalid collection name');
    }
    if (!/^[a-zA-Z_][a-zA-Z0-9_.]*$/.test(field)) {
      throw new Error('Invalid field name');
    }

    const safeFilter = sanitiseFilter(filter || {});
    const values = await db.collection(collection).distinct(field, safeFilter);

    return res.json({ success: true, count: values.length, data: values });
  } catch (err) {
    console.error('[API ERROR]', err.message);
    return res.status(400).json({ success: false, error: err.message });
  }
});

